    "proofSteps": [
      "Start with the expression containing an irrational denominator.",
      "Identify the multiplier needed to make the denominator a rational number (usually θ·³b or its conjugate).",
      "Multiply both numerator and denominator by this multiplier.",
      "Simplify the resulting fraction."
    ],
    "commonMistakes": [
      {
        "mistake": "Only multiplying the numerator, not the denominator.",
        "correction": "Always multiply BOTH top and bottom to keep the value equivalent.",
        "example": "Incorrect: 1/θ·³2 = θ·³2. Correct: (1├©θ·³2)/(θ·³2├©θ·³2) = θ·³2/2."
      },
      {
        "mistake": "Forgetting that θ·³a ├© θ·³a = a, not θ·³(a┬▓).",
        "correction": "Remember the root and its square cancel out to give just 'a'.",
        "example": "θ·³3 ├© θ·³3 = 3."
      }
    ],
    "sections": [
      {
        "heading": "What is Rationalizing?",
        "explanation": "Rationalizing the denominator means removing square roots from the bottom of a fraction. It makes numbers easier to compare and calculate with, just like converting 1/0.5 to 2.",
        "keyPoints": [
          "We multiply by '1' in a special form (like θ·³x/θ·³x).",
          "The value doesn't change, only the appearance."
        ],
        "examples": [
          "Converting 1/θ·³3 to θ·³3/3 makes it easier to estimate as roughly 0.577.",
          "In geometry, side lengths are often left in radical form for precision before final calculation."
        ],
        "whyItMatters": "Standard mathematical practice requires rational denominators for consistency and further algebraic manipulation.",
        "terminology": [
          "Rationalizing",
          "Conjugate",
          "Surds"
        ],
        "detailedExplanation": "When you have a fraction like 1/θ·³2, the denominator is an irrational number. By multiplying by θ·³2/θ·³2 (which equals 1), we turn the bottom into θ·³4 = 2, which is rational.",
        "observedIn": [
          "Solving quadratic equations",
          "Trigonometry problems involving angles like 30┬░ or 60┬░"
        ],
        "visualSupport": [
          "diagram-1: Number line showing the length of θ·³2."
        ],
        "visualAssets": [],
        "importantNotes": [
          "Never forget to simplify the final fraction if possible (e.g., 4/θ·³8 becomes θ·³2)."
        ],
        "memoryTechniques": [
          "Think 'Clean Up': Make the bottom clean and whole."
        ],
        "conceptSummary": [
          "Multiply top and bottom by a root to remove it from the denominator."
        ]
      }
    ],
    "definitions": [
      {
        "term": "Rationalizing",
        "definition": "The process of eliminating radicals (square roots) from the denominator of a fraction."
      },
      {
        "term": "Conjugate",
        "definition": "For an expression like (a + θ·³b), its conjugate is (a - θ·³b). Their product removes the root."
      }
    ],
    "workedExamples": [
      {
        "title": "Rationalizing a Simple Surd Denominator",
        "problem": "Simplify: 5 / θ·³3",
        "diagramRef": null,
        "given": [
          "Expression: 5/θ·³3"
        ],
        "formula": [
          "Multiply numerator and denominator by the root in the denominator."
        ],
        "steps": [
          "Identify θ·³3 as the multiplier.",
          "Perform multiplication on both parts of the fraction.",
          "Simplify the result."
        ],
        "solutionSteps": [
          {
            "text": "Multiply numerator and denominator by \\sqrt{3}",
            "displayLatex": "\\frac{5}{\\sqrt{3}} \\times \\frac{\\sqrt{3}}{\\sqrt{3}}"
          },
          {
            "text": "Simplify the denominator (since \\sqrt{3} \\times \\sqrt{3} = 3)",
            "displayLatex": "\\frac{5\\sqrt{3}}{3}"
          }
        ],
        "reasoning": [
          {
            "text": "We use this method because the denominator must be rational.",
            "latex": "\\sqrt{x} \\cdot \\sqrt{x} = x"
          }
        ],
        "explanation": "By multiplying by θ·³3/θ·³3, we create a perfect square in the bottom (3) while keeping the value equal to the original fraction. The numerator becomes 5θ·³3.",
        "finalAnswer": {
          "text": "\\frac{5\\sqrt{3}}{3}",
          "displayLatex": "\\frac{5\\sqrt{3}}{3}"
        },
        "latex": "",
        "displayLatex": ""
      }
    ],
    "revisionSection": {
      "definitions": [
        "Rationalizing: Removing roots from the denominator."
      ],
      "formulas": [
        "\\frac{a}{\\sqrt{b}} = \\frac{a\\sqrt{b}}{b}"
      ],
      "facts": [
        "θ·³2 θ¬· 1.414, θ·³3 θ¬· 1.732"
