      ]
    },
    "selfCheckQuestions": [
      "What is 2/θ·³5 in rationalized form?",
      "Why do we multiply both numerator and denominator?"
    ],
    "quickSummary": [
      "Rationalizing makes fractions easier to handle by removing roots from the bottom."
    ],
    "keyTerms": [
      "Surds",
      "Denominator",
      "Conjugate"
    ],
    "fillInTheBlanks": [
      {
        "prompt": "To rationalize 1/θ·³7, we multiply by ________ / θ·³7.",
        "answer": "θ·³7"
